import React, { useState, useEffect } from 'react';

function Dashboard() {
  const [data, setData] = useState([]);

  // Fungsi ambil data dari Flask
  const fetchData = async () => {
    try {
      const response = await fetch('http://127.0.0.1:5000/api/trash');
      const result = await response.json();
      setData(result);
    } catch (error) {
      console.error("Gagal ambil data:", error);
    }
  };

  useEffect(() => {
    fetchData();
    const interval = setInterval(fetchData, 5000); // Update tiap 5 detik
    return () => clearInterval(interval);
  }, []);

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <h1 style={styles.title}>Smart Trash Bin Monitoring</h1>
        <p style={styles.subtitle}>Sistem Monitoring Tempat Sampah Real-time</p>
      </header>

      <div style={styles.statsContainer}>
        <div style={styles.card}>
          <h3>Total Sampah</h3>
          <p style={styles.cardValue}>{data.length} Data</p>
        </div>
        <div style={styles.card}>
          <h3>Status Terakhir</h3>
          <p style={styles.cardValue}>{data[data.length - 1]?.status || "-"}</p>
        </div>
      </div>

      <div style={styles.tableContainer}>
        <table style={styles.table}>
          <thead>
            <tr>
              <th style={styles.th}>ID Bin</th>
              <th style={styles.th}>Tipe</th>
              <th style={styles.th}>Kapasitas (%)</th>
              <th style={styles.th}>Status</th>
              <th style={styles.th}>Waktu</th>
            </tr>
          </thead>
          <tbody>
            {data.length > 0 ? (
              data.map((item, index) => (
                <tr key={index} style={styles.tr}>
                  <td style={styles.td}>{item.bin_id}</td>
                  <td style={styles.td}>{item.type}</td>
                  <td style={styles.td}>
                    <div style={styles.progressBg}>
                      <div style={{...styles.progressFill, width: `${item.percentage}%`}}></div>
                      {Math.round(item.percentage)}%
                    </div>
                  </td>
                  <td style={styles.td}>
                    <span style={item.status === "penuh" ? styles.badgeFull : styles.badgeEmpty}>
                      {item.status}
                    </span>
                  </td>
                  <td style={styles.td}>{item.created_at}</td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="5" style={styles.tdCenter}>Belum ada data masuk dari sensor...</td>
              </tr>
            )}
          </tbody>
        </table>
      </div>
    </div>
  );
}

// 🎨 DESAIN CSS (Internal Styles)
const styles = {
  container: { padding: '40px', backgroundColor: '#f4f7f6', minHeight: '100vh', fontFamily: 'Arial, sans-serif' },
  header: { marginBottom: '30px', textAlign: 'center' },
  title: { color: '#2c3e50', fontSize: '2.5rem', marginBottom: '10px' },
  subtitle: { color: '#7f8c8d', fontSize: '1.1rem' },
  statsContainer: { display: 'flex', gap: '20px', marginBottom: '30px', justifyContent: 'center' },
  card: { backgroundColor: '#fff', padding: '20px', borderRadius: '12px', boxShadow: '0 4px 6px rgba(0,0,0,0.1)', minWidth: '200px', textAlign: 'center' },
  cardValue: { fontSize: '1.5rem', fontWeight: 'bold', color: '#27ae60' },
  tableContainer: { backgroundColor: '#fff', borderRadius: '12px', overflow: 'hidden', boxShadow: '0 10px 25px rgba(0,0,0,0.05)' },
  table: { width: '100%', borderCollapse: 'collapse' },
  th: { backgroundColor: '#2c3e50', color: '#fff', padding: '15px', textAlign: 'left' },
  tr: { borderBottom: '1px solid #eee' },
  td: { padding: '15px', color: '#34495e' },
  tdCenter: { padding: '40px', textAlign: 'center', color: '#bdc3c7' },
  progressBg: { backgroundColor: '#ecf0f1', borderRadius: '10px', overflow: 'hidden', textAlign: 'center', position: 'relative', height: '25px', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '0.8rem', fontWeight: 'bold' },
  progressFill: { position: 'absolute', left: 0, top: 0, height: '100%', backgroundColor: '#3498db', zIndex: 0, transition: 'width 0.5s ease' },
  badgeFull: { backgroundColor: '#e74c3c', color: '#fff', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem' },
  badgeEmpty: { backgroundColor: '#2ecc71', color: '#fff', padding: '5px 12px', borderRadius: '20px', fontSize: '0.8rem' }
};

export default Dashboard;
